{
  "learning_outcomes": [
    {
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics",
      "topic": "Thermodynamics and Energy Transformations",
      "outcomes": [
        "Apply calorimetry techniques to measure enthalpy changes (∆U and ∆H)",
        "Analyze the relationship between Gibbs Energy Change and chemical equilibrium",
        "Evaluate the spontaneity of reactions based on thermodynamic parameters",
        "Interpret reaction enthalpy in the context of different types of chemical reactions"
      ]
    },
    {
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium",
      "topic": "Chemical and Ionic Equilibrium Systems",
      "outcomes": [
        "Distinguish between physical and chemical processes in equilibrium",
        "Calculate and apply the Law of Chemical Equilibrium and Equilibrium Constant (K)",
        "Analyze the relationship between Reaction Quotient (Q), Equilibrium Constant (K), and Gibbs Energy (G)",
        "Predict factors affecting equilibria in homogeneous and heterogeneous systems",
        "Apply ionic equilibrium concepts to acids, bases, buffer solutions, and solubility"
      ]
    },
    {
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions",
      "topic": "Redox Processes and Electrode Dynamics",
      "outcomes": [
        "Classify reactions using classical ideas of oxidation and reduction",
        "Analyze redox reactions in terms of electron transfer mechanisms",
        "Determine oxidation numbers for elements in compounds",
        "Relate redox reactions to electrode processes"
      ]
    },
    {
      "unit_name": "Organic Chemistry – Some Basic Principles and Techniques",
      "chapter_name": "Organic Chemistry – Some Basic Principles and Techniques",
      "topic": "Organic Chemistry Principles and Techniques",
      "outcomes": [
        "Represent organic compounds structurally based on carbon tetravalence",
        "Apply IUPAC nomenclature rules to classify and name organic compounds",
        "Identify and categorize different types of isomerism",
        "Analyze fundamental concepts in organic reaction mechanisms",
        "Apply methods for purification and qualitative/quantitative analysis of organic compounds"
      ]
    },
    {
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons",
      "topic": "Hydrocarbon Classification and Properties",
      "outcomes": [
        "Classify hydrocarbons into alkanes, alkenes, alkynes, and aromatic compounds",
        "Analyze the relationship between structure and properties of hydrocarbons",
        "Evaluate carcinogenic potential and toxicity of specific hydrocarbons"
      ]
    },
    {
      "unit_name": "s & p Block Elements (Formative Assessment)",
      "chapter_name": "",
      "topic": "Periodic Trends and Elemental Properties (Formative)",
      "outcomes": [
        "Correlate electronic configuration with position in the periodic table",
        "Analyze trends in atomic/ionic radii, ionization enthalpy, and hydration enthalpy across periods and groups",
        "Identify unique behavior of the first element in each group"
      ]
    },
    {
      "unit_name": "The Gaseous State (Formative Assessment)",
      "chapter_name": "",
      "topic": "Gaseous State and Kinetic Theory (Formative)",
      "outcomes": [
        "Apply qualitative gas laws to predict changes in gaseous systems",
        "Analyze deviations from the Ideal Gas Equation"
      ]
    }
  ]
}
